import mysql.connector as msql
from mysql.connector import Error
import os

def read_blob_data(filename):
    with open(filename, 'rb') as fileobj:
        binary_data = fileobj.read()
    return binary_data

def insertBLOB(filepath):
    try:
        connection = msql.connect(host='localhost',
                                 database='database_name',
                                 user='user_name', 
                                 password='password')
                                 
        cursor = connection.cursor()        
        # Enable local_infile in MySQL config (assuming it is enabled by default)
        cursor.execute("SET GLOBAL local_infile=1")
        query = """LOAD DATA INFILE '{}' 
                   INTO TABLE table_name
                   FIELDS TERMINATED BY ',' 
                   LINES TERMINATED BY '\n' """.format(filepath)
        
        cursor.execute(query)
        connection.commit()
        print("Data imported successfully")
    except Error as e :
        print("Error while connecting to MySQL", e)
        
    finally:
        if (connection.is_connected()):
            cursor.close()
            connection.close()
            print("MySQL connection is closed")
            
filepath = input('Enter the file path: ')   # Get file path from user
insertBLOB(filepath)